#include "controller.h"

static void controller_set_safe_vent(controller_t *controller)
{
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

static void controller_apply_output(controller_t *controller, bool compressor_on, bool vent_open, controller_state_t state)
{
    controller->compressor_on = compressor_on;
    controller->vent_open = vent_open;
    controller->state = state;
}

static bool sensor_timeout_check(controller_t *controller, uint32_t now_ms)
{
    /* Check if either sensor is stale for more than 1000ms */
    if (!controller->has_valid_pressure || (now_ms - controller->last_pressure_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        return true;
    }
    if (!controller->has_valid_door || (now_ms - controller->last_door_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        return true;
    }
    return false;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_vent(controller);
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };
    bool previous_compressor_on;
    bool previous_vent_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_compressor_on = controller->compressor_on;
    previous_vent_open = controller->vent_open;
    previous_state = controller->state;

    /* Handle sensor timeout or invalid input - always go to safe vent */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_PRESSURE ||
        input.kind == CONTROLLER_INPUT_INVALID_DOOR) {
        controller->has_valid_pressure = false;
        controller->has_valid_door = false;
        controller_set_safe_vent(controller);
    } else if (input.kind == CONTROLLER_INPUT_PRESSURE) {
        /* Update pressure freshness */
        controller->has_valid_pressure = true;
        controller->last_pressure_kpa = input.pressure_kpa;
        controller->last_pressure_ms = input.now_ms;
    } else if (input.kind == CONTROLLER_INPUT_DOOR_OPEN) {
        /* Door open - update door freshness and go to safe vent */
        controller->has_valid_door = true;
        controller->door_closed = false;
        controller->last_door_ms = input.now_ms;
        controller_set_safe_vent(controller);
    } else if (input.kind == CONTROLLER_INPUT_DOOR_CLOSED) {
        /* Door closed - update door freshness */
        controller->has_valid_door = true;
        controller->door_closed = true;
        controller->last_door_ms = input.now_ms;
    } else {
        /* CONTROLLER_INPUT_NONE - no new sensor data, check timeout */
    }

    /* Check for sensor timeout condition */
    bool timeout = sensor_timeout_check(controller, input.now_ms);
    if (timeout) {
        controller->has_valid_pressure = false;
        controller->has_valid_door = false;
        controller_set_safe_vent(controller);
        output.timed_out = true;
    }

    /* If we're in safe vent state from a timeout or fault, just return */
    if (controller->state == CONTROLLER_STATE_SAFE_VENT && (timeout || input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT || input.kind == CONTROLLER_INPUT_INVALID_PRESSURE || input.kind == CONTROLLER_INPUT_INVALID_DOOR)) {
        output.compressor_on = controller->compressor_on;
        output.vent_open = controller->vent_open;
        output.state = controller->state;
        output.state_name = controller_state_name(controller->state);
        output.changed =
            (previous_compressor_on != controller->compressor_on) ||
            (previous_vent_open != controller->vent_open) ||
            (previous_state != controller->state);
        return output;
    }

    /* Apply control policy based on current state and inputs */
    if (!controller->door_closed) {
        /* Door is open - stay in safe vent */
        controller_set_safe_vent(controller);
    } else if (timeout) {
        /* Sensor timeout - stay in safe vent */
        controller_set_safe_vent(controller);
    } else if (controller->has_valid_pressure && !controller->has_valid_door) {
        /* Have pressure but no valid door info yet - stay in safe vent until both are valid */
        controller_set_safe_vent(controller);
    } else {
        /* Both sensors valid, apply control policy */
        int pressure = controller->last_pressure_kpa;

        if (pressure < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
            /* Low pressure - pressurize */
            controller_apply_output(controller, true, false, CONTROLLER_STATE_PRESSURIZING);
        } else if (pressure > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
            /* High pressure - relieve */
            controller_apply_output(controller, false, true, CONTROLLER_STATE_RELIEVING);
        } else {
            /* In band (40-60) - hold previous safe output */
            /* Don't change state, keep current compressor/vent settings */
            if (controller->state != CONTROLLER_STATE_HOLDING) {
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        }
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_compressor_on != controller->compressor_on) ||
        (previous_vent_open != controller->vent_open) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
