/* Apply control policy based on current state and inputs */
 /* Only apply control policy if BOTH sensors are valid */
 bool both_sensors_valid = controller->has_valid_pressure && controller->has_valid_door;

 if (!controller->door_closed) {
     /* Door is open - stay in safe vent */
     controller_set_safe_vent(controller);
 } else if (timeout) {
     /* Sensor timeout - stay in safe vent */
     controller_set_safe_vent(controller);
 } else if (!both_sensors_valid) {
     /* Don't have both sensors valid yet - stay in safe vent */
     controller_set_safe_vent(controller);
 } else {
     /* Both sensors valid, apply control policy */
     int pressure = controller->last_pressure_kpa;

     if (pressure < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
         /* Low pressure - pressurize */
         controller_apply_output(controller, true, false, CONTROLLER_STATE_PRESSURIZING);
     } else if (pressure > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
         /* High pressure - relieve */
         controller_apply_output(controller, false, true, CONTROLLER_STATE_RELIEVING);
     } else {
         /* In band (40-60) - hold previous safe output */
         /* Don't change state, keep current compressor/vent settings */
         if (controller->state != CONTROLLER_STATE_HOLDING) {
             controller->state = CONTROLLER_STATE_HOLDING;
         }
     }
 }

